 1	import * as React from 'react';
 2	
 3	import { WizardTab } from '@catalog/wizard/tabs';
 4	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 5	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { PATHS_TO_HIGHLIGHT } from '@kubevirt-utils/resources/vm/utils/constants';
 8	import { ListPageBody, ListPageCreateButton } from '@openshift-console/dynamic-plugin-sdk';
 9	import { PageSection, PageSectionVariants } from '@patternfly/react-core';
10	
11	import NetworkInterfaceList from './components/list/NetworkInterfaceList';
12	import WizardNetworkInterfaceModal from './components/modal/WizardNetworkInterfaceModal';
13	
14	const WizardNetworkTab: WizardTab = ({ updateVM, vm }) => {
15	  const { t } = useKubevirtTranslation();
16	  const { createModal } = useModal();
17	
18	  const actionText = t('Add network interface');
19	
20	  return (
21	    <PageSection variant={PageSectionVariants.light}>
22	      <ListPageBody>
23	        <SidebarEditor
24	          onResourceUpdate={(newVM) => updateVM(newVM)}
25	          pathsToHighlight={PATHS_TO_HIGHLIGHT.NETWORK_TAB}
26	          resource={vm}
27	        >
28	          <ListPageCreateButton
29	            onClick={() =>
30	              createModal(({ isOpen, onClose }) => (
31	                <WizardNetworkInterfaceModal
32	                  headerText={actionText}
33	                  isOpen={isOpen}
34	                  onClose={onClose}
35	                  updateVM={updateVM}
36	                  vm={vm}
37	                />
38	              ))
39	            }
40	            className="list-page-create-button-margin"
41	          >
42	            {actionText}
43	          </ListPageCreateButton>
44	
45	          <NetworkInterfaceList vm={vm} />
46	        </SidebarEditor>
47	      </ListPageBody>
48	    </PageSection>
49	  );
50	};
51	
52	export default WizardNetworkTab;

